SELECT developer_id, COUNT(commit_id) AS total_commits
FROM commits
GROUP BY developer_id;

SELECT COUNT(developer_id) AS developer_count
FROM developers
WHERE role = 'developer';

SELECT repo_name, repo_url, COUNT(*) AS repository_count
FROM repositories
GROUP BY repo_name, repo_url;

SELECT developer_id, name, affiliation, role, phone_number
FROM developers
ORDER BY date_joined DESC;

SELECT developer_id, name, email, affiliation, role
FROM developers
ORDER BY name ASC;
